To write unit tests for the `retry` function using `pytest`, we need to cover the happy path, edge cases, and error cases. Here's how you can structure the tests:

```python
import pytest

def retry(fn, max_attempts: int = 3):
    for attempt in range(max_attempts):
        try:
            return fn()
        except Exception:
            if attempt == max_attempts - 1:
                raise

# Test cases

def test_retry_success_on_first_attempt():
    """Test that the function succeeds on the first attempt."""
    def successful_fn():
        return "success"

    result = retry(successful_fn)
    assert result == "success"

def test_retry_success_on_second_attempt():
    """Test that the function succeeds on the second attempt."""
    attempts = [0]

    def flaky_fn():
        attempts[0] += 1
        if attempts[0] < 2:
            raise Exception("fail")
        return "success"

    result = retry(flaky_fn)
    assert result == "success"
    assert attempts[0] == 2

def test_retry_success_on_last_attempt():
    """Test that the function succeeds on the last attempt."""
    attempts = [0]

    def flaky_fn():
        attempts[0] += 1
        if attempts[0] < 3:
            raise Exception("fail")
        return "success"

    result = retry(flaky_fn)
    assert result == "success"
    assert attempts[0] == 3

def test_retry_fails_after_max_attempts():
    """Test that the function raises an exception after max attempts."""
    attempts = [0]

    def always_failing_fn():
        attempts[0] += 1
        raise Exception("fail")

    with pytest.raises(Exception, match="fail"):
        retry(always_failing_fn, max_attempts=3)
    assert attempts[0] == 3

def test_retry_with_custom_max_attempts():
    """Test that the function respects custom max_attempts."""
    attempts = [0]

    def flaky_fn():
        attempts[0] += 1
        if attempts[0] < 2:
            raise Exception("fail")
        return "success"

    result = retry(flaky_fn, max_attempts=2)
    assert result == "success"
    assert attempts[0] == 2

def test_retry_with_zero_attempts():
    """Test that the function raises an exception immediately with zero attempts."""
    attempts = [0]

    def always_failing_fn():
        attempts[0] += 1
        raise Exception("fail")

    with pytest.raises(Exception, match="fail"):
        retry(always_failing_fn, max_attempts=0)
    assert attempts[0] == 1

def test_retry_with_negative_attempts():
    """Test that the function raises a ValueError for negative max_attempts."""
    with pytest.raises(ValueError):
        retry(lambda: "success", max_attempts=-1)

# Add a check for negative max_attempts in the function
def retry(fn, max_attempts: int = 3):
    if max_attempts < 0:
        raise ValueError("max_attempts must be non-negative")
    for attempt in range(max_attempts):
        try:
            return fn()
        except Exception:
            if attempt == max_attempts - 1:
                raise
```

### Explanation:

1. **Happy Path**: Tests where the function succeeds on the first, second, or last attempt.
2. **Edge Cases**: Tests with custom `max_attempts` and zero attempts.
3. **Error Cases**: Tests where the function fails after the maximum number of attempts and where `max_attempts` is negative.

The function is also modified to raise a `ValueError` if `max_attempts` is negative, ensuring robustness.
